#!/usr/bin/env bash
set -e; SRC=$(cd "$(dirname "$0")" && pwd); DEST=${ADXC_INSTALL_DIR:-/opt/adxc}; ACTIVATE_ROOT=no; for a in "$@"; do case "$a" in --activate-root) ACTIVATE_ROOT=yes;; *) echo "Unknown option: $a"; exit 1;; esac; done; [ "$(id -u)" -eq 0 ] || { echo "ERROR: install.sh must be run as root" >&2; exit 1; }; . "$SRC/lib/adxc-colors.sh"; adxc_title "aDXC-GAMA INSTALLER"; printf '%-24s : %s\n' Source "$SRC" Destination "$DEST" Version "$(cat "$SRC/VERSION")"; rm -rf "$DEST"; mkdir -p "$DEST"; cp -a "$SRC"/. "$DEST"/; find "$DEST" -type d -exec chmod 755 {} \;; find "$DEST" -type f -exec chmod 644 {} \;; find "$DEST/bin" "$DEST/admin" "$DEST/commands" "$DEST/templates/profile-templates" -type f -exec chmod 755 {} \;; chmod 755 "$DEST/install.sh" "$DEST/uninstall.sh"; adxc_section "INSTALLATION COMPLETE"; for item in "Dashboard:adxc" "Help:adxc-help" "All commands:adxc-help --list-all" "Profile inventory:adxc-profiles" "Message admin:adxc-admin messages" "Create message:adxc-msg-create" "Create profile:adxc-create-profile" "Create command:adxc-create-command" "Custom commands:adxc-cmd"; do printf '%-24b : %s\n' "${ADXC_GREEN}${item%%:*}${ADXC_RESET}" "${item#*:}"; done; if [ "$ACTIVATE_ROOT" = yes ]; then "$DEST/admin/adxc-enable-user.sh" root --role admin --force >/dev/null; adxc_ok "Root runtime created: /root/.adxc"; echo "Run: source /root/.adxc/activate.sh && adxc"; else adxc_warn "Root runtime not created. Use --activate-root if root should run adxc directly."; fi; adxc_line
